import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/tag/src/tag.component.js';
const tagName = 'made-tag';
Component.define(tagName);
/**
 * @summary Tags categorize and organize items using descriptive keywords for quick recognition and navigation.
 * @documentation '../stories/tag.mdx'
 *
 * @dependency made-icon-button
 *
 * @fires mde-dismiss {CustomEvent} - Fired when the dismiss button is clicked (dismissible tags only).
 *
 * @slot - The tag's main content (required).
 * @slot start - Used to place content before the tag text. Typically used for icons or avatars.
 * @slot end - Used to place content after the tag text. Typically used for icons.
 *
 * @csspart base - The component's base wrapper.
 * @csspart content - The container that wraps the default slot content.
 * @csspart dismiss-button - The dismiss button (when dismissible).
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {
        onMdeDismiss: 'mde-dismiss'
    },
    displayName: 'MadeTag'
});
export default reactWrapper;
